import{_ as t,o,c as r,a2 as n}from"./chunks/framework.Crpw6aS5.js";const u=JSON.parse('{"title":"Linux wireless-regdb (db.txt) — where limits look highest","description":"Notes on Linux wireless-regdb (db.txt) — where limits look highest.","frontmatter":{"title":"Linux wireless-regdb (db.txt) — where limits look highest","description":"Notes on Linux wireless-regdb (db.txt) — where limits look highest."},"headers":[],"relativePath":"misc/inbox-imports/git-kernel-wireless-regdb-max-eirp-notes.md","filePath":"misc/inbox-imports/git-kernel-wireless-regdb-max-eirp-notes.md"}'),a={name:"misc/inbox-imports/git-kernel-wireless-regdb-max-eirp-notes.md"};function i(s,e,l,d,g,h){return o(),r("div",null,[...e[0]||(e[0]=[n('<h1 id="linux-wireless-regdb-db-txt-—-maximum-eirp-highlights" tabindex="-1">Linux wireless-regdb (<code>db.txt</code>) — maximum EIRP highlights <a class="header-anchor" href="#linux-wireless-regdb-db-txt-—-maximum-eirp-highlights" aria-label="Permalink to &quot;Linux wireless-regdb (`db.txt`) — maximum EIRP highlights&quot;">​</a></h1><h2 id="source" tabindex="-1">Source <a class="header-anchor" href="#source" aria-label="Permalink to &quot;Source&quot;">​</a></h2><ul><li>Type: text (analysis of regulatory database format; not a full webpage ingest)</li><li>Origin: <a href="https://git.kernel.org/pub/scm/linux/kernel/git/sforshee/wireless-regdb.git/plain/db.txt?id=HEAD" target="_blank" rel="noreferrer">wireless-regdb <code>db.txt</code> on kernel.org</a> (upstream canonical path); local parse used a saved copy when automated fetch hit bot protection (Anubis).</li><li>Imported: 2026-05-13</li><li>Images: none in the source material for this note (numeric rules only).</li></ul><h2 id="content" tabindex="-1">Content <a class="header-anchor" href="#content" aria-label="Permalink to &quot;Content&quot;">​</a></h2><h3 id="how-db-txt-encodes-power" tabindex="-1">How <code>db.txt</code> encodes power <a class="header-anchor" href="#how-db-txt-encodes-power" aria-label="Permalink to &quot;How `db.txt` encodes power&quot;">​</a></h3><p>In the Linux wireless regulatory database text file:</p><ul><li>A parenthesized value <strong>without</strong> a unit after the frequency tuple, e.g. <code>(30)</code>, is <strong>dBm</strong> (EIRP).</li><li>Values like <code>(100 mW)</code> or <code>(4000 mW)</code> are explicit <strong>milliwatt</strong> EIRP limits.</li></ul><p>Rules are per <strong>country</strong> ISO code (<code>country XX:</code>) and <strong>frequency range</strong>; the kernel applies the domain that matches the configured regulatory country. Comparing “who has the biggest number” only makes sense <strong>for the same band</strong> (2.4 GHz, 5 GHz, 6 GHz, 60 GHz / 802.11ad, etc.), because a 60 GHz rule is not comparable to home 2.4/5 GHz Wi‑Fi in practice.</p><h3 id="highest-single-rule-in-the-analyzed-snapshot-any-band" tabindex="-1">Highest single rule in the analyzed snapshot (any band) <a class="header-anchor" href="#highest-single-rule-in-the-analyzed-snapshot-any-band" aria-label="Permalink to &quot;Highest single rule in the analyzed snapshot (any band)&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:right;">Order</th><th>Country</th><th>Approx. peak</th><th>Band / comment</th></tr></thead><tbody><tr><td style="text-align:right;">1</td><td><strong>CN</strong></td><td><strong>44 dBm</strong> (~25.1 W)</td><td>60 GHz segment <code>59400–63720 MHz</code> (802.11ad-style numbering in file)</td></tr><tr><td style="text-align:right;">2</td><td><strong>AU</strong></td><td><strong>20 000 mW</strong> (20 W)</td><td>Very wide 60 GHz span <code>57000–71000 MHz</code>, marked <code>NO-OUTDOOR</code> in upstream rules</td></tr></tbody></table><p>So for <strong>raw maximum EIRP attached to one line</strong> in that file, <strong>China (CN)</strong> edges Australia on the mid 60 GHz slice (44 dBm vs 20 W), while <strong>Australia</strong> still carries an extremely high explicit <strong>20 W</strong> rule on a broad 60 GHz allocation.</p><h3 id="sub‐7-ghz-only-2-4-5-6-ghz-—-ordinary-wi‐fi-context" tabindex="-1">Sub‑7 GHz only (2.4 / 5 / ~6 GHz — “ordinary” Wi‑Fi context) <a class="header-anchor" href="#sub‐7-ghz-only-2-4-5-6-ghz-—-ordinary-wi‐fi-context" aria-label="Permalink to &quot;Sub‑7 GHz only (2.4 / 5 / ~6 GHz — “ordinary” Wi‑Fi context)&quot;">​</a></h3><p>Excluding 57–71 GHz style rules:</p><ul><li><strong>Australia (AU)</strong> stands out with <strong>4000 mW (36 dBm)</strong> on <strong>2.4 GHz</strong> (<code>2400–2483.5</code>) and again on <strong>5.7–5.85 GHz</strong> (<code>5730–5850</code>).</li><li><strong>Panama (PA)</strong> and <strong>Hong Kong (HK)</strong> show <strong>36 dBm</strong> on several sub‑7 GHz entries in the same database snapshot (not necessarily 4 W on 2.4 GHz like AU).</li></ul><p>Many FCC-style domains cap <strong>2.4 GHz</strong> around <strong>30 dBm (1 W)</strong> for typical rules; <strong>30 dBm</strong> on 5 GHz U‑NII appears widely (US, and many <code>DFS-FCC</code> countries).</p><h3 id="compliance-non‐negotiable" tabindex="-1">Compliance (non‑negotiable) <a class="header-anchor" href="#compliance-non‐negotiable" aria-label="Permalink to &quot;Compliance (non‑negotiable)&quot;">​</a></h3><p>Devices must operate under the regulations <strong>where the transmitter is physically located</strong>. Selecting a country code or reg domain only to chase a higher line in <code>db.txt</code> is <strong>not</strong> a substitute for local law and can cause harmful interference.</p><h3 id="fetch-reproducibility" tabindex="-1">Fetch / reproducibility <a class="header-anchor" href="#fetch-reproducibility" aria-label="Permalink to &quot;Fetch / reproducibility&quot;">​</a></h3><ul><li>Direct scripted fetch of <code>git.kernel.org</code> may return an Anubis challenge page instead of <code>db.txt</code>; cloning the <a href="https://git.kernel.org/pub/scm/linux/kernel/git/sforshee/wireless-regdb.git/" target="_blank" rel="noreferrer">wireless-regdb</a> repository or downloading <code>db.txt</code> in a browser is often more reliable for humans.</li><li>Re-run analysis by parsing lines matching <code>country XX:</code> blocks and tab-indented <code>(...), (...)</code> rules; convert bare integers to mW via (10^{\\mathrm{dBm}/10}) for ranking.</li></ul><h2 id="key-takeaways" tabindex="-1">Key takeaways <a class="header-anchor" href="#key-takeaways" aria-label="Permalink to &quot;Key takeaways&quot;">​</a></h2><ul><li><strong>“Best country for maximum power” is undefined until you name the band</strong> (2.4 vs 5 vs 6 vs 60 GHz); global maxima in <code>db.txt</code> are often <strong>60 GHz</strong> rules, not laptop Wi‑Fi.</li><li>For <strong>classic Wi‑Fi bands</strong> in this snapshot, <strong>AU</strong> had the strongest <strong>explicit mW</strong> limits on 2.4 GHz and 5.7–5.85 GHz.</li><li>For <strong>one-line peak including 60 GHz</strong>, <strong>CN</strong> had the highest <strong>dBm</strong> value (44 dBm) on a mid 60 GHz range; <strong>AU</strong> had <strong>20 W</strong> on a wide 60 GHz rule.</li><li>Always follow <strong>local</strong> regulatory domain; <code>db.txt</code> is a reference encoding of national rules, not permission to operate.</li></ul>',21)])])}const m=t(a,[["render",i]]);export{u as __pageData,m as default};
